mapper.select:
SELECT post_id, user_id, title, content, category, view_count, like_count, status, created_at, updated_at FROM ( SELECT ROW_NUMBER() OVER (ORDER BY post_id DESC) AS rn, post_id, user_id, title, content, category, view_count, like_count, status, created_at, updated_at FROM COMMUNITY WHERE status = 'DISPLAY'
AND category = #{category}
AND title LIKE '%' || #{searchKeyword} || '%'
AND content LIKE '%' || #{searchKeyword} || '%'
AND ( title LIKE '%' || #{searchKeyword} || '%' OR content LIKE '%' || #{searchKeyword} || '%' )
AND user_id LIKE '%' || #{searchKeyword} || '%'
) WHERE rn BETWEEN #{startRow} AND #{endRow}

